const ITEMS = [
  { src: '/img1.png', bg: '#F4845F' },
  { src: '/img2.png', bg: '#6BBF7A' },
  { src: '/img3.png', bg: '#E882B4' },
  { src: '/img4.png', bg: '#6EB5FF' },
];

// Roles derivados do índice ativo
const getRoles = (activeIndex: number, total: number) => ({
  center: activeIndex,
  left:  (activeIndex + total - 1) % total,
  right: (activeIndex + 1) % total,
  back:  (activeIndex + 2) % total,
});

// Lock de animação — ignora cliques durante transição
const [activeIndex, setActiveIndex] = useState(0);
const [isAnimating, setIsAnimating] = useState(false);

const navigate = (dir: 'next' | 'prev') => {
  if (isAnimating) return;
  setIsAnimating(true);
  setActiveIndex(prev => dir === 'next'
    ? (prev + 1) % ITEMS.length
    : (prev + ITEMS.length - 1) % ITEMS.length
  );
  setTimeout(() => setIsAnimating(false), 650);
};

code.role_styles:
// Estilos por papel — aplicados via object spread
const roleStyles = (role: string, isMobile: boolean) => {
  const T = 'transform 650ms cubic-bezier(0.4,0,0.2,1), filter 650ms cubic-bezier(0.4,0,0.2,1), opacity 650ms cubic-bezier(0.4,0,0.2,1), left 650ms cubic-bezier(0.4,0,0.2,1)';
  switch (role) {
    case 'center': return {
      left: '50%',
      height: isMobile ? '60%' : '92%',
      bottom: isMobile ? '22%' : 0,
      transform: `translateX(-50%) scale(${isMobile ? 1.25 : 1.68})`,
      filter: 'none',
      opacity: 1,
      zIndex: 20,
      transition: T,
    };
    case 'left': return {
      left: isMobile ? '20%' : '30%',
      height: isMobile ? '16%' : '28%',
      bottom: isMobile ? '32%' : '12%',
      transform: 'translateX(-50%) scale(1)',
      filter: 'blur(2px)',
      opacity: 0.85,
      zIndex: 10,
      transition: T,
    };
    case 'right': return {
      left: isMobile ? '80%' : '70%',
      height: isMobile ? '16%' : '28%',
      bottom: isMobile ? '32%' : '12%',
      transform: 'translateX(-50%) scale(1)',
      filter: 'blur(2px)',
      opacity: 0.85,
      zIndex: 10,
      transition: T,
    };
    case 'back': return {
      left: '50%',
      height: isMobile ? '13%' : '22%',
      bottom: isMobile ? '32%' : '12%',
      transform: 'translateX(-50%) scale(1)',
      filter: 'blur(4px)',
      opacity: 1,
      zIndex: 5,
      transition: T,
    };
    default: return {};
  }
};

